using std::vector;
using std::array;
using std::min;
using std::max;
using std::string;
using std::pair;
using std::make_pair;
using std::ofstream;
using std::runtime_error;

namespace coacd
{

    using vec3d = std::array<double, 3>;
    using vec3i = std::array<int, 3>;
    using vec3s = std::array<short, 3>;
    constexpr double INF = std::numeric_limits<double>::max();

    struct HalfEdge
    {
        int head;
        std::list<HalfEdge>::iterator opposite;
    };

    class Edge
    {
    public:
        vec3d p0, p1;
        Edge() {}
        Edge(vec3d _p0, vec3d _p1)
        {
            p0 = _p0;
            p1 = _p1;
        }
    };

    class Plane
    {
    public:
        double a, b, c, d;
        bool pFlag;       // whether three point form exists
        vec3d p0, p1, p2; // three point form
        short CutSide(vec3d inP0, vec3d inP1, vec3d inP2, Plane plane);
        short BoolSide(vec3d p);
        short Side(vec3d p, double eps = 1e-6);
        bool IntersectSegment(vec3d segmentP1, vec3d segmentP2, vec3d &pi, double eps = 1e-6);
        Plane();
        Plane(double _a, double _b, double _c, double _d)
        {
            a = _a;
            b = _b;
            c = _c;
            d = _d;
            pFlag = false;
        }
    };

    bool SamePointDetect(vec3d p0, vec3d p1, float eps=1e-5);
    bool SameVectorDirection(vec3d v, vec3d w);
    vec3d CrossProduct(vec3d v, vec3d w);
    vec3d CalFaceNormal(vec3d p1, vec3d p2, vec3d p3);
    double Area(vec3d p0, vec3d p1, vec3d p2);
    double Volume(vec3d p1, vec3d p2, vec3d p3);
    void Diagonalize(const array<array<double, 3>, 3>& A, array<array<double, 3>, 3>& Q, array<array<double, 3>, 3>& D);

    inline double pt_norm(vec3d p)
    {
        return sqrt(p[0] * p[0] + p[1] * p[1] + p[2] * p[2]);
    }

    inline bool SameVectorDirection(vec3d v, vec3d w)
    {
        if (v[0] * w[0] + v[1] * w[1] + v[2] * w[2] > 0)
            return true;
        return false;
    }

    inline vec3d CrossProduct(vec3d v, vec3d w)
    {
        vec3d res;
        res[0] = v[1] * w[2] - v[2] * w[1];
        res[1] = v[2] * w[0] - v[0] * w[2];
        res[2] = v[0] * w[1] - v[1] * w[0];

        return res;
    }

    inline short Plane::CutSide(vec3d inP0, vec3d inP1, vec3d inP2, Plane plane)
    {
        vec3d normal = CalFaceNormal(inP0, inP1, inP2);
        if (normal[0] * plane.a > 0 || normal[1] * plane.b > 0 || normal[2] * plane.c > 0)
            return -1;
        return 1;
    }

    inline short Plane::BoolSide(vec3d p)
    {
        double res = p[0] * a + p[1] * b + p[2] * c + d;
        if (res > 0)
            return 1;
        else
            return -1;
    }

    inline short Plane::Side(vec3d p, double eps)
    {
        double res = p[0] * a + p[1] * b + p[2] * c + d;
        if (res > eps)
            return 1;
        else if (res < -1 * eps)
            return -1;
        return 0;
    }

    inline bool Plane::IntersectSegment(vec3d segmentP1, vec3d segmentP2, vec3d &pi, double eps)
    {
        pi[0] = (segmentP1[0] * b * segmentP2[1] + segmentP1[0] * c * segmentP2[2] + segmentP1[0] * d - segmentP2[0] * b * segmentP1[1] - segmentP2[0] * c * segmentP1[2] - segmentP2[0] * d) / (a * segmentP2[0] - a * segmentP1[0] + b * segmentP2[1] - b * segmentP1[1] + c * segmentP2[2] - c * segmentP1[2]);
        pi[1] = (a * segmentP2[0] * segmentP1[1] + c * segmentP1[1] * segmentP2[2] + segmentP1[1] * d - a * segmentP1[0] * segmentP2[1] - c * segmentP1[2] * segmentP2[1] - segmentP2[1] * d) / (a * segmentP2[0] - a * segmentP1[0] + b * segmentP2[1] - b * segmentP1[1] + c * segmentP2[2] - c * segmentP1[2]);
        pi[2] = (a * segmentP2[0] * segmentP1[2] + b * segmentP2[1] * segmentP1[2] + segmentP1[2] * d - a * segmentP1[0] * segmentP2[2] - b * segmentP1[1] * segmentP2[2] - segmentP2[2] * d) / (a * segmentP2[0] - a * segmentP1[0] + b * segmentP2[1] - b * segmentP1[1] + c * segmentP2[2] - c * segmentP1[2]);

        if (min(segmentP1[0] - eps, segmentP2[0] - eps) <= pi[0] && pi[0] <= max(segmentP1[0] + eps, segmentP2[0] + eps) &&
            min(segmentP1[1] - eps, segmentP2[1] - eps) <= pi[1] && pi[1] <= max(segmentP1[1] + eps, segmentP2[1] + eps) &&
            min(segmentP1[2] - eps, segmentP2[2] - eps) <= pi[2] && pi[2] <= max(segmentP1[2] + eps, segmentP2[2] + eps))
            return true;
        return false;
    }

    template <typename T>
    struct PointCloud
    {
        struct Point
        {
            T x, y, z;
        };

        std::vector<Point> pts;

        // Must return the number of data points
        inline size_t kdtree_get_point_count() const { return pts.size(); }

        // Returns the dim'th component of the idx'th point in the class:
        // Since this is inlined and the "dim" argument is typically an immediate value, the
        //  "if/else's" are actually solved at compile time.
        inline T kdtree_get_pt(const size_t idx, const size_t dim) const
        {
            if (dim == 0)
                return pts[idx].x;
            else if (dim == 1)
                return pts[idx].y;
            else
                return pts[idx].z;
        }

        // Optional bounding-box computation: return false to default to a standard bbox computation loop.
        //   Return true if the BBOX was already computed by the class and returned in "bb" so it can be avoided to redo it again.
        //   Look at bb.size() to find out the expected dimensionality (e.g. 2 or 3 for point clouds)
        template <class BBOX>
        bool kdtree_get_bbox(BBOX & /* bb */) const { return false; }
    };

    template <typename T>
    void vec2PointCloud(PointCloud<T> &point, vector<vec3d> V)
    {
        point.pts.resize(V.size());
        for (size_t i = 0; i < V.size(); i++)
        {
            point.pts[i].x = V[i][0];
            point.pts[i].y = V[i][1];
            point.pts[i].z = V[i][2];
        }
    }
}

