#ifndef BT_CONVEX_HULL_COMPUTER_H
#define BT_CONVEX_HULL_COMPUTER_H


using namespace std;

/// Convex hull implementation based on Preparata and Hong
/// See http://code.google.com/p/bullet/issues/detail?id=275
/// Ole Kniemeyer, MAXON Computer GmbH
class btConvexHullComputer {
// private:
//     btScalar compute(vector<array<double, 3>> points);

public:
    class Edge {
    private:
        int32_t next;
        int32_t reverse;
        int32_t targetVertex;

        friend class btConvexHullComputer;

    public:
        int32_t getSourceVertex() const
        {
            return (this + reverse)->targetVertex;
        }

        int32_t getTargetVertex() const
        {
            return targetVertex;
        }

        const Edge* getNextEdgeOfVertex() const // clockwise list of all edges of a vertex
        {
            return this + next;
        }

        const Edge* getNextEdgeOfFace() const // counter-clockwise list of all edges of a face
        {
            return (this + reverse)->getNextEdgeOfVertex();
        }

        const Edge* getReverseEdge() const
        {
            return this + reverse;
        }
    };

    // Vertices of the output hull
    btAlignedObjectArray<btVector3> vertices;

    // Edges of the output hull
    btAlignedObjectArray<Edge> edges;

    // Faces of the convex hull. Each entry is an index into the "edges" array pointing to an edge of the face. Faces are planar n-gons
    btAlignedObjectArray<int32_t> faces;

    /*
		Compute convex hull of "count" vertices stored in "coords". "stride" is the difference in bytes
		between the addresses of consecutive vertices. If "shrink" is positive, the convex hull is shrunken
		by that amount (each face is moved by "shrink" length units towards the center along its normal).
		If "shrinkClamp" is positive, "shrink" is clamped to not exceed "shrinkClamp * innerRadius", where "innerRadius"
		is the minimum distance of a face to the center of the convex hull.

		The returned value is the amount by which the hull has been shrunken. If it is negative, the amount was so large
		that the resulting convex hull is empty.

		The output convex hull can be found in the member variables "vertices", "edges", "faces".
		*/

    // btScalar compute(vector<array<float, 3>> points)
    // {
    //     return compute(points);
    // }

    // // same as above, but double precision
    // btScalar compute(vector<array<double, 3>> points)
    // {
    //     return compute(points);
    // }
    btScalar compute(vector<array<double, 3>> points, btScalar shrink, btScalar shrinkClamp);
};

#endif //BT_CONVEX_HULL_COMPUTER_H

// ----- End CoACD Bullet btConvexHullComputer -----

