/// Vertex index hasher
template <>
struct hash<::Riemann::COACDConvexDecomposition::CDT::VertInd>
{
    /// Hash operator
    std::size_t operator()(const ::Riemann::COACDConvexDecomposition::CDT::VertInd& vi) const
    {
        return std::hash<std::size_t>()(vi.t);
    }
};

/// Triangle index hasher
template <>
struct hash<::Riemann::COACDConvexDecomposition::CDT::TriInd>
{
    /// Hash operator
    std::size_t operator()(const ::Riemann::COACDConvexDecomposition::CDT::TriInd& vi) const
    {
        return std::hash<std::size_t>()(vi.t);
    }
};

#endif // CDT_USE_STRONG_TYPING

/// Edge hasher
template <>
struct hash<::Riemann::COACDConvexDecomposition::CDT::Edge>
{
    /// Hash operator
    std::size_t operator()(const ::Riemann::COACDConvexDecomposition::CDT::Edge& e) const
    {
        return hashEdge(e);
    }

private:
    static void hashCombine(std::size_t& seed, const ::Riemann::COACDConvexDecomposition::CDT::VertInd& key)
    {
#ifdef CDT_CXX11_IS_SUPPORTED
        typedef std::hash<::Riemann::COACDConvexDecomposition::CDT::VertInd> Hasher;
#else
        typedef boost::hash<::Riemann::COACDConvexDecomposition::CDT::VertInd> Hasher;
#endif
        seed ^= Hasher()(key) + 0x9e3779b9 + (seed << 6) + (seed >> 2);
    }

    static std::size_t hashEdge(const ::Riemann::COACDConvexDecomposition::CDT::Edge& e)
    {
        std::size_t seed(0);
        hashCombine(seed, e.v1());
        hashCombine(seed, e.v2());
        return seed;
    }
};

