template <typename T>
struct hash<::Riemann::COACDConvexDecomposition::CDT::V2d<T> >
{
    size_t operator()(const ::Riemann::COACDConvexDecomposition::CDT::V2d<T>& xy) const
    {
#ifdef CDT_CXX11_IS_SUPPORTED
        typedef std::hash<T> Hasher;
#else
        typedef boost::hash<T> Hasher;
#endif
        return Hasher()(xy.x) ^ Hasher()(xy.y);
    }
};
